    if ((sleep_time != expected_sleep_time)) begin
      `FATAL(("Sleep Test FAILED: unexpected sleep instruction duration. Expected=%d, Got=%d",expected_sleep_time,sleep_time));
    end else begin
      `INFO(("Sleep Test PASSED"), ADI_VERBOSITY_LOW);
    end
  endtask

